$pageTitle='VP3 Clip Editor';$pageDescription='Create a public short-form rendition from a protected Stonefellow video and send it to the VP3 Clips discovery feed.';$pageClass='membership-page admin-catalog-page';require_once __DIR__.'/../includes/admin_catalog.php';require_once __DIR__.'/../includes/vp3_clips.php';$id=max(0,(int)($_GET['id']??$_POST['id']??0));
if(($_SERVER['REQUEST_METHOD']??'GET')==='POST'){$action=(string)($_POST['action']??'save');try{if($action==='save'){$id=sf_vp3_clip_save($_POST,sf_current_user_id());sf_admin_flash('success','Clip draft saved.');}elseif($action==='render'){$id=sf_vp3_clip_save($_POST,sf_current_user_id());$result=sf_vp3_clip_render($id);sf_admin_flash(!empty($result['ok'])?'success':'error',!empty($result['ok'])?'Vertical clip and poster rendered.':'Render failed: '.($result['error']??'unknown error'));}elseif($action==='publish'){$id=sf_vp3_clip_save($_POST,sf_current_user_id());$clip=sf_vp3_clip_by_id($id);if(!$clip||!is_file((string)$clip['rendered_video_path']))throw new RuntimeException('Render the clip before publishing.');$result=sf_vp3_clip_publish($id);sf_admin_flash(!empty($result['ok'])?'success':'error',!empty($result['ok'])?'Clip sent to VP3. Current status: '.($result['data']['publication_status']??'pending').'.':'Publish failed: '.($result['error']??'unknown error'));}elseif($action==='sync'){$result=sf_vp3_clip_sync($id);sf_admin_flash(!empty($result['ok'])?'success':'error',!empty($result['ok'])?'VP3 moderation status and analytics synchronized.':'Sync failed: '.($result['error']??'unknown error'));}elseif($action==='withdraw'){$result=sf_vp3_clip_withdraw($id);sf_admin_flash(!empty($result['ok'])?'success':'error',!empty($result['ok'])?'Clip withdrawn from VP3 distribution.':'Withdrawal failed: '.($result['error']??'unknown error'));}}catch(Throwable $e){sf_admin_flash('error',$e->getMessage());}$target='admin/vp3-clip-editor.php'.($id>0?'?id='.$id:'');sf_admin_redirect(sf_url($target));}
$clip=$id>0?sf_vp3_clip_by_id($id):null;$sources=sf_vp3_clip_sources();$receipt=sf_license_receipt()?:[];$defaultDestination=(string)($receipt['base_url']??'');require __DIR__.'/../includes/header.php';sf_admin_shell_start('VP3 Clips',$clip?'Edit Clip':'Create Clip','Choose a ready protected-media object, define the trim and poster frame, confirm rights, render locally, and syndicate the public rendition.','vp3-clips');
