rl']??$defaultDestination)?>"></label><label>Destination button label<input name="destination_label" maxlength="80" value="<?=sf_admin_h($clip['destination_label']??'Watch more')?>"></label><label>Rights owner<input name="rights_owner_name" maxlength="190" required value="<?=sf_admin_h($clip['rights_owner_name']??($receipt['customer_name']??'Stonefellow'))?>"></label><label>Rights expiration<input type="datetime-local" name="rights_expires_at" value="<?=sf_admin_h(!empty($clip['rights_expires_at'])?str_replace(' ','T',substr((string)$clip['rights_expires_at'],0,16)):'')?>"></label></div><label class="sf-admin-checkbox"><input type="checkbox" name="rights_confirmed" value="1" <?=!empty($clip['rights_confirmed'])?'checked':''?> required> I confirm this platform controls the rights needed to publish this public clip to VP3.</label><div class="clip-actions"><button name="action" value="save">Save draft</button><button name="action" value="render">Save & render</button><?php if($clip&&is_file((string)$clip['rendered_video_path'])):?><button name="action" value="publish">Publish / update VP3</button><?php endif;?></div></form><?php if($clip):?><div class="clip-actions" style="margin-top:12px"><form method="post"><?=sf_csrf_field()?><input type="hidden" name="id" value="<?=(int)$clip['id']?>"><button name="action" value="sync">Sync status + analytics</button></form><?php if(!empty($clip['central_publication_uuid'])&&$clip['local_status']!=='withdrawn'):?><form method="post"><?=sf_csrf_field()?><input type="hidden" name="id" value="<?=(int)$clip['id']?>"><button name="action" value="withdraw">Withdraw from VP3</button></form><?php endif;?></div><?php endif;?></section><aside class="sf-admin-panel"><div class="sf-admin-panel-head"><div><span class="sf-panel-eyebrow">Public rendition</span><h2>Preview & state</h2></div></div><div class="clip-preview"><?php if($clip&&is_file((string)$clip['rendered_video_path'])):?><video controls playsinline poster="<?=sf_admin_h(sf_vp3_clip_public_url($clip,'poster'))?>"><source src="<?=sf_admin_h(sf_vp3_clip_public_url($clip,'video'))?>" type="video/mp4"></video><?php else:?><span>Render the clip to preview the public 9:16 rendition.</span><?php endif;?></div><?php if($clip):?><div class="sf-admin-detail-list"><div><span>Local state</span><strong><?=sf_admin_h($clip['local_status'])?></strong></div><div><span>VP3 publication</span><strong><?=sf_admin_h($clip['central_publication_status']??'not submitted')?></strong></div><div><span>Moderation</span><strong><?=sf_admin_h($clip['central_moderation_status']??'not reviewed')?></strong></div><div><span>Rights</span><strong><?=sf_admin_h($clip['central_rights_status']??'local confirmation')?></strong></div><div><span>Feed</span><strong><?=!empty($clip['central_feed_eligible'])?'Eligible':'Held'?></strong></div><div><span>Publication UUID</span><strong><?=sf_admin_h($clip['central_publication_uuid']??'—')?></strong></div></div><?php if(!empty($clip['last_error'])):?><p class="sf-admin-alert sf-admin-alert-error"><?=sf_admin_h($clip['last_error'])?></p><?php endif;?><?php endif;?></aside></div>
